(window.webpackJsonp=window.webpackJsonp||[]).push([[300],{927:function(n,r){n.exports="\x3c!-- \r\ntitle: ADB\r\nsort: \r\n--\x3e \r\n# ADB命令入门\r\n\r\n## 操作\r\n\r\n```powershell\r\n# 安装应用\r\nadb install *.apk\r\n# 屏幕截图\r\nadb shell screencap /sdcard/screen.png\r\n# 文件传送至电脑\r\nadb pull /sdcard/screen.png d:\\test\\\r\n# 点击屏幕 100,100像素\r\nadb shell input tap 100 100\r\n# 滑动 开始坐标 结束坐标 延迟时间\r\nadb shell input swipe 500 1500 500 500 500\r\n# 设备信息 -s \r\nadb devices\r\n```\r\n\r\n## 模拟按键\r\n\r\n```powershell\r\nadb shell input keyevent <keycode>\r\n```\r\n\r\n| keycode | 含义                           |\r\n| :------ | :----------------------------- |\r\n| 3       | HOME 键                        |\r\n| 4       | 返回键                         |\r\n| 5       | 打开拨号应用                   |\r\n| 6       | 挂断电话                       |\r\n| 24      | 增加音量                       |\r\n| 25      | 降低音量                       |\r\n| 26      | 电源键                         |\r\n| 27      | 拍照（需要在相机应用里）       |\r\n| 64      | 打开浏览器                     |\r\n| 82      | 菜单键                         |\r\n| 85      | 播放/暂停                      |\r\n| 86      | 停止播放                       |\r\n| 87      | 播放下一首                     |\r\n| 88      | 播放上一首                     |\r\n| 122     | 移动光标到行首或列表顶部       |\r\n| 123     | 移动光标到行末或列表底部       |\r\n| 126     | 恢复播放                       |\r\n| 127     | 暂停播放                       |\r\n| 164     | 静音                           |\r\n| 176     | 打开系统设置                   |\r\n| 187     | 切换应用                       |\r\n| 207     | 打开联系人                     |\r\n| 208     | 打开日历                       |\r\n| 209     | 打开音乐                       |\r\n| 210     | 打开计算器                     |\r\n| 220     | 降低屏幕亮度                   |\r\n| 221     | 提高屏幕亮度                   |\r\n| 223     | 系统休眠                       |\r\n| 224     | 点亮屏幕                       |\r\n| 231     | 打开语音助手                   |\r\n| 276     | 如果没有 wakelock 则让系统休眠 |"}}]);